import{_ as n,c as s,o as a,d as l}from"./app.661b9247.js";const v=JSON.parse('{"title":"nvm的简介、安装、使用","description":"","frontmatter":{},"headers":[{"level":2,"title":"一、nvm是什么？","slug":"一、nvm是什么","link":"#一、nvm是什么","children":[]},{"level":2,"title":"二、nvm的安装","slug":"二、nvm的安装","link":"#二、nvm的安装","children":[{"level":3,"title":"1.windows包下载地址","slug":"_1-windows包下载地址","link":"#_1-windows包下载地址","children":[]},{"level":3,"title":"2.点击如下文件进行安装","slug":"_2-点击如下文件进行安装","link":"#_2-点击如下文件进行安装","children":[]}]},{"level":2,"title":"三、使用","slug":"三、使用","link":"#三、使用","children":[{"level":3,"title":"3. 常见命令","slug":"_3-常见命令","link":"#_3-常见命令","children":[]}]},{"level":2,"title":"4. 其他命令","slug":"_4-其他命令","link":"#_4-其他命令","children":[]},{"level":2,"title":"四、nvm的一些命令","slug":"四、nvm的一些命令","link":"#四、nvm的一些命令","children":[]}],"relativePath":"Document/Node/nvm的简介、安装、使用.md","lastUpdated":1669828334000}'),e={name:"Document/Node/nvm的简介、安装、使用.md"},p=l(`<h1 id="nvm的简介、安装、使用" tabindex="-1">nvm的简介、安装、使用 <a class="header-anchor" href="#nvm的简介、安装、使用" aria-hidden="true">#</a></h1><h2 id="一、nvm是什么" tabindex="-1">一、nvm是什么？ <a class="header-anchor" href="#一、nvm是什么" aria-hidden="true">#</a></h2><p>nvm是一个<a href="https://so.csdn.net/so/search?q=node&amp;spm=1001.2101.3001.7020" target="_blank" rel="noreferrer">node</a>的版本管理工具，可以简单操作node版本的切换、安装、查看...等等，与npm不同的是，npm是依赖包的管理工具。</p><h2 id="二、nvm的安装" tabindex="-1">二、nvm的安装 <a class="header-anchor" href="#二、nvm的安装" aria-hidden="true">#</a></h2><h3 id="_1-windows包下载地址" tabindex="-1">1.windows包下载地址 <a class="header-anchor" href="#_1-windows包下载地址" aria-hidden="true">#</a></h3><p>百度网盘：<a href="https://pan.baidu.com/s/1EUc-e2Ai-lXXQkjlB8jmlA" target="_blank" rel="noreferrer">https://pan.baidu.com/s/1EUc-e2Ai-lXXQkjlB8jmlA</a> 提取码：vg9l</p><p>github下载地址：<a href="https://github.com/coreybutler/nvm-windows/releases" target="_blank" rel="noreferrer">https://github.com/coreybutler/nvm-windows/releases</a></p><ul><li>nvm-noinstall.zip： 绿色免安装版本，但是使用之前需要配置</li><li>nvm-setup.zip：安装版，下载之后点击安装，无需配置就可以使用</li></ul><h3 id="_2-点击如下文件进行安装" tabindex="-1">2.点击如下文件进行安装 <a class="header-anchor" href="#_2-点击如下文件进行安装" aria-hidden="true">#</a></h3><h4 id="_1-安装" tabindex="-1">（1）安装 <a class="header-anchor" href="#_1-安装" aria-hidden="true">#</a></h4><p><img src="https://img-blog.csdnimg.cn/4f264237810d48e283e54f7f37af142e.png" alt=""></p><p><img src="https://img-blog.csdnimg.cn/33cd315d026041aa903c02c78b30828f.png" alt=""></p><p>（注意这里：默认安装到C盘，之后就不用配置环境变量了）</p><p><img src="https://img-blog.csdnimg.cn/2860d17bfce641c0b48e539a780c0e03.png" alt=""></p><p><img src="https://img-blog.csdnimg.cn/0f69ee63bd8f4ba6b33dfaa44b0ab562.png" alt=""></p><p><img src="https://img-blog.csdnimg.cn/8cc7c83b44194154afac3d60652575ef.png" alt=""></p><p>之后finish就完成安装了。完成可以以下方式检测</p><p><img src="https://img-blog.csdnimg.cn/98d9b56fa2384770a8d465cdaa86b5aa.png" alt=""></p><p>⚪如果安装到D盘，则需要配置相对应的环境，如图：（输入相对应的文件位置）</p><p><img src="https://img-blog.csdnimg.cn/5153ed11090b4f4db700b6cacb029134.png" alt=""></p><p><img src="https://img-blog.csdnimg.cn/5083a0ac725d45c695d1af3403ab2950.png" alt=""></p><h4 id="_2-配置" tabindex="-1">（2）配置 <a class="header-anchor" href="#_2-配置" aria-hidden="true">#</a></h4><p>找到nvm文件位置，点开setting</p><p><img src="https://img-blog.csdnimg.cn/7f086b492f344d7cbe3a8a8c8c235154.png" alt=""></p><p><img src="https://img-blog.csdnimg.cn/406cf50b3a4f496db02b854498030c5e.png" alt=""></p><p>然后在它后面输入以下代码：（这是配置镜像源）</p><div class="language-js line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">node_mirror: https:</span><span style="color:#7F848E;font-style:italic;">//npm.taobao.org/mirrors/node/</span></span>
<span class="line"><span style="color:#ABB2BF;">npm_mirror: https:</span><span style="color:#7F848E;font-style:italic;">//npm.taobao.org/mirrors/npm/</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="三、使用" tabindex="-1">三、使用 <a class="header-anchor" href="#三、使用" aria-hidden="true">#</a></h2><p>1.先卸载之前的node.js</p><p>2.在刚刚的nvm文件位置打开cmd</p><p>3.输入以下代码查看nvm可安装的node版本</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">nvm </span><span style="color:#98C379;">ls</span><span style="color:#ABB2BF;">                      </span><span style="color:#98C379;">//</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">看安装的所有node.js的版本</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">nvm </span><span style="color:#98C379;">list</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">available</span><span style="color:#ABB2BF;">          </span><span style="color:#98C379;">//</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">查显示可以安装的所有node.js的版本</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>4.安装所对应的版本。</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">nvm </span><span style="color:#98C379;">install</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">版本号</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">//</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">例如：nvm</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">install</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">14.19.0</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>5.切换到安装的版本</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">nvm </span><span style="color:#98C379;">use</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">版本号</span><span style="color:#ABB2BF;">           </span><span style="color:#98C379;">//</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">切换到使用指定的nodejs版本</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>6.检测是否切换完成，新开一个cmd</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">node </span><span style="color:#D19A66;">-v</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-常见命令" tabindex="-1">3. 常见命令 <a class="header-anchor" href="#_3-常见命令" aria-hidden="true">#</a></h3><blockquote><p><strong>1. nvm -v //查看nvm版本</strong></p><ul><li><p>nvm --version ：显示 nvm 版本 <strong>2. nvm list //显示版本列表</strong></p></li><li><p>nvm list ：显示已安装的版本（同 nvm list installed</p></li><li><p>nvm list installed：显示已安装的版本</p></li><li><p>nvm list available：显示所有可以下载的版本 <strong>3. nvm install <a href="//xn--node-ke9gmd864dt6hk5z1m5c.js">//安装指定版本node.js</a></strong></p></li><li><p>nvm install 14.5.0：安装 14.5.0 版本的 node.js</p></li><li><p>nvm install latest：安装最新版本 <strong>4. nvm use //使用指定版本node</strong></p></li><li><p>nvm use 14.5.0： 切换到 14.5.0 版本的 node.js</p></li><li><p>--lts // 自动切换到长期支持版本</p></li><li><p>--lts=[LTS name] // 自动切换到指定名称的node长期支持版本 <strong>5. nvm uninstall [version] //卸载指定版本 node</strong></p></li><li><p>nvm uninstall 14.5.0：卸载到 14.5.0 版本的 node.js</p></li><li><p>nvm uninstall --lts // 卸载长期支持版本的node</p></li><li><p>nvm uninstall --lts=[LTS name] // 卸载一个指定名称的长期支持版本的node <strong>6. nvm --help</strong> **//**<strong>显示命令行帮助信息</strong></p></li></ul></blockquote><p>[ ps：在运行nvm install 的时候，有可能会出现无权限安装的问题，请 <strong>以管理员身份</strong> 运行 <strong>cmd</strong> ]</p><h2 id="_4-其他命令" tabindex="-1">4. 其他命令 <a class="header-anchor" href="#_4-其他命令" aria-hidden="true">#</a></h2><blockquote><ul><li><p>nvm deactivate // 取消当前nvm命令行效果 <strong>1. nvm</strong> <strong>查看node版本</strong></p></li><li><p>nvm current // 查看当前使用的node版本</p></li><li><p>nvm ls // 查看所有本地可用的node版本</p></li><li><p>nvm ls [version] // 参看指定版本</p></li><li><p>nvm ls-remote // 查看所有可用远程版本</p></li><li><p>--lts // 查看所有长期支持版本</p></li><li><p>nvm ls-remote [version] // 参看所有node的指定远程版本</p></li><li><p>--lts // 查看所有node长期支持版本</p></li><li><p>--lts=[LTS name] // 仅查看指定名称的长期支持版本 <strong>2. nvm</strong> <strong>版本别名</strong></p></li><li><p>nvm alias [pattern] // 显示所有以[pattern]开头的版本别名</p></li><li><p>nvm alias [name] [version] // 给版本[version]设置一个别名</p></li><li><p>nvm unalias [name] // 删除[name]的版本别名 <strong>3. nvm和npm</strong></p></li><li><p>nvm <strong>install</strong>-latest-npm // 在当前node版本中，将npm升级到最新版</p></li><li><p>nvm <strong>reinstall</strong>-packages [version] // 在全局重新安装npm，从[version]版本到当前版本 <strong>4. npm which显示安装路径</strong></p></li></ul><p>npm <strong>which</strong> [current | [version]] //显示已安装node的安装路径。 <strong>5. nvm缓存</strong></p><ul><li><p>nvm <strong>cache</strong> dir // 显示nvm的缓存目录</p></li><li><p>nvm <strong>cache</strong> clear // 清楚nvm的缓存目录 <strong>6. nvm运行node</strong></p></li><li><p>nvm <strong>exec</strong> [--silent] [version] [command] <strong>// 在[version]运行命令[command]</strong></p></li><li><p><code>**nvm exec 4.8.3 node app.js**</code> //Run <code>node app.js</code> with the PATH pointing to node 4.8.3</p></li><li><p>nvm <strong>run</strong> [--silent] [version] [[args]] <strong>// 在[version]以参数[args]运行node</strong> <strong>--</strong></p></li><li><p><code>**nvm run 6.10.3 app.js**</code> //Run app.js using node 6.10.3 <strong>7. 设置镜像</strong></p></li><li><p><code>nvm node_mirror [url]</code> ：设置node镜像。默认是<a href="https://nodejs.org/dist/%E3%80%82%E5%A6%82%E6%9E%9C%E4%B8%8D%E5%86%99url%EF%BC%8C%E5%88%99%E4%BD%BF%E7%94%A8%E9%BB%98%E8%AE%A4url%E3%80%82%E8%AE%BE%E7%BD%AE%E5%90%8E%E5%8F%AF%E8%87%B3%E5%AE%89%E8%A3%85%E7%9B%AE%E5%BD%95settings.txt" target="_blank" rel="noreferrer">https://nodejs.org/dist/。如果不写url，则使用默认url。设置后可至安装目录settings.txt</a>文件查看，也可直接在该文件操作。</p></li><li><p><code>nvm npm_mirror [url]</code> ：设置npm镜像。<a href="https://github.com/npm/cli/archive/%E3%80%82%E5%A6%82%E6%9E%9C%E4%B8%8D%E5%86%99url%EF%BC%8C%E5%88%99%E4%BD%BF%E7%94%A8%E9%BB%98%E8%AE%A4url%E3%80%82%E8%AE%BE%E7%BD%AE%E5%90%8E%E5%8F%AF%E8%87%B3%E5%AE%89%E8%A3%85%E7%9B%AE%E5%BD%95settings.txt" target="_blank" rel="noreferrer">https://github.com/npm/cli/archive/。如果不写url，则使用默认url。设置后可至安装目录settings.txt</a>文件查看，也可直接在该文件操作。 <strong>8. 版本管理</strong></p></li><li><p><code>nvm on</code> ：开启node.js版本管理。</p></li><li><p><code>nvm off</code> ：关闭node.js版本管理。</p></li></ul></blockquote><h2 id="四、nvm的一些命令" tabindex="-1">四、nvm的一些命令 <a class="header-anchor" href="#四、nvm的一些命令" aria-hidden="true">#</a></h2><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro"><code><span class="line"><span style="color:#ABB2BF;">nvm命令行操作命令</span></span>
<span class="line"><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">,nvm nvm list 是查找本电脑上所有的node版本</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">- </span><span style="color:#98C379;">nvm</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">list</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">查看已经安装的版本</span></span>
<span class="line"><span style="color:#ABB2BF;">- </span><span style="color:#98C379;">nvm</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">list</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">installed</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">查看已经安装的版本</span></span>
<span class="line"><span style="color:#ABB2BF;">- </span><span style="color:#98C379;">nvm</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">list</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">available</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">查看网络可以安装的版本</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">2</span><span style="color:#ABB2BF;">,nvm install 安装最新版本nvm</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">3</span><span style="color:#ABB2BF;">,nvm use [version] </span><span style="color:#7F848E;font-style:italic;">## 切换使用指定的版本node</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">4</span><span style="color:#ABB2BF;">,nvm ls 列出所有版本</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">5</span><span style="color:#ABB2BF;">,nvm current显示当前版本</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">6</span><span style="color:#ABB2BF;">,nvm alias [name] [version] </span><span style="color:#7F848E;font-style:italic;">## 给不同的版本号添加别名</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">7</span><span style="color:#ABB2BF;">,nvm unalias [name] </span><span style="color:#7F848E;font-style:italic;">## 删除已定义的别名</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">8</span><span style="color:#ABB2BF;">,nvm reinstall-packages [version] </span><span style="color:#7F848E;font-style:italic;">## 在当前版本node环境下，重新全局安装指定版本号的npm包</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">9</span><span style="color:#ABB2BF;">,nvm on 打开nodejs控制</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">10</span><span style="color:#ABB2BF;">,nvm off 关闭nodejs控制</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">11</span><span style="color:#ABB2BF;">,nvm proxy 查看设置与代理</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">12</span><span style="color:#ABB2BF;">,nvm node_mirror [url] 设置或者查看setting.txt中的node_mirror，如果不设置的默认是 https://nodejs.org/dist/</span></span>
<span class="line"><span style="color:#ABB2BF;">　　nvm </span><span style="color:#98C379;">npm_mirror</span><span style="color:#ABB2BF;"> [url] </span><span style="color:#98C379;">设置或者查看setting.txt中的npm_mirror,如果不设置的话默认的是：</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">https://github.com/npm/npm/archive/.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">13</span><span style="color:#ABB2BF;">,nvm uninstall [version] 卸载制定的版本</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">14</span><span style="color:#ABB2BF;">,nvm use [version] [arch] 切换制定的node版本和位数</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">15</span><span style="color:#ABB2BF;">,nvm root [path] 设置和查看root路径</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">16</span><span style="color:#ABB2BF;">,nvm version 查看当前的版本</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br></div></div>`,45),r=[p];function o(i,t,c,m,d,b){return a(),s("div",null,r)}const g=n(e,[["render",o]]);export{v as __pageData,g as default};
